                    case 2: operationType = "BUILD_MESSAGE_INFO (Schema Definition)";
                            console.log(`[zzaj] Schema Info accessed. Schema String: "${obj2[1]}" Fields: ${JSON.stringify(obj2.slice(2))}`);
                            break;
                    case 3: operationType = "NEW_MUTABLE_INSTANCE"; break;
                    case 4: operationType = "NEW_BUILDER";
                            if (result && result.$className) {
                                console.log(`[zzaj] New builder created: ${result.$className}`);
                                // Further hooks can be placed on zzai methods here
                                hookZzaiBuilder(result); // Call a helper function to hook builder methods
                            }
                            break;
                    case 5: operationType = "GET_DEFAULT_INSTANCE"; break;
                    default: operationType = "UNKNOWN"; break;
                }
                console.log(`[zzaj.zzb] Operation: ${operationType} (i=${i}). Result: ${result}`);

                if (operationType === "NEW_MUTABLE_INSTANCE" && result instanceof zzaj) {
                    // Inspect the created zzaj object for field values if possible
                    console.log(`  -> Created zzaj instance. zze: ${result.zze.value}, zzf: ${result.zzf.value}, zzg: ${result.zzg.value}`);
                    // Note: direct field access .value might not always work if they are objects.
                    // You might need to call getter methods if they exist, or inspect the object's memory.
                }

                return result;
            };

            function hookZzaiBuilder(builderInstance) {
                // Assuming setters like 'setZzf' or 'setZzg' exist on the builder
                // Actual method names would need to be discovered through static analysis of zzai.java
                // Example: builderInstance.setZzf.implementation = function(val) { ... }
                console.log(`[Frida] Now hooking methods of zzaj builder: ${builderInstance.$className}`);
                // Iterate over prototype to find potential setter methods
                for (var methodName in builderInstance) {
                    if (methodName.startsWith('setZz')) { // Generic check for obfuscated setters
                        try {
                            const originalMethod = builderInstance[methodName];
                            if (typeof originalMethod === 'function') {
                                console.log(`  -> Hooking builder method: ${methodName}`);
                                builderInstance[methodName].implementation = function(value) {
                                    console.log(`    -> ${methodName} called with value: ${JSON.stringify(value)}`);
